// // This module compares two 16-bit inputs A and B and outputs the following:
// - A_not_equal_B (low if A is equal to B)
// - A_not_greater_B (low if A is greater than B)
// - A_not_less_B (low if A is less than B)
module comparator_16bit (
    input [15:0] A,
    input [15:0] B,
    output reg A_equals_B,
    output reg A_greater_B,
    output reg A_less_B
);
    always @(*) begin
        A_equals_B = (A == B);
        A_greater_B = (A > B);
        A_less_B = (A < B);
    end
endmodule

